      "n": 6,
      "column": "left",
      "text": "Ne pamett winnu / tad\nwinna tew usturrehs / mihle\nwinnu/ tad winna tew pasar-\ngahs.\n"
    },
    {
      "n": 7,
      "column": "left",
      "text": "Jo ta Gudriba irr tas Ge-\nfahkums/ famanto Gudribu/ un\nar wiſfu tarvu Padohmu faman-\nto Saprafchanu.\n"
    },
    {
      "n": 8,
      "column": "left",
      "text": "Turr winnu angsti / tad\nwinna tew pa-augstinahs/ win-\na tew Goddá zels/ ja tu win-\nu apkampsi.\n"
    },
    {
      "n": 9,
      "column": "left",
      "text": "Winna dohs weenu jan ku\nBlihtumu tawat Galwai / wee-\nn frahſchnu Krohui winna tew\nahwanahs.\n"
    },
    {
      "n": 10,
      "column": "left",
      "text": "Klaufajs mans Behrns/\nin veenem mannu Wallodu /\nad watrofees tew tahs Dsihwí-\nas Gaddi.\n"
    },
    {
      "n": 11,
      "column": "left",
      "text": "Es pamahzu tew to Zet-\nu tahs Gudribas/ es weddiſchu\new us ibstenu Tekku.\n"
    },
    {
      "n": 12,
      "column": "left",
      "text": "Ka kad tu eiji/ tawa Ge-\nchana tew ne buhs gruhta / un\nad tu tezzi/ ka tu few ne dau-\nisees.\n"
    },
    {
      "n": 13,
      "column": "left",
      "text": "Satwer to Pamahzifcha-\nn/ ne atstahjees no tahs / targi\no/ jo ta irr tawa Dsihwiba.\n"
    },
    {
      "n": 14,
      "column": "left",
      "text": "Us to Besdeewigu Tek-\nahm ne nahzi/ un us to Launo\nettu ne sper tawu Kahju.\n"
    },
    {
      "n": 15,
      "column": "left",
      "text": "Atmett to/ ne statga pahr\nvinnu/ atkahpees no ta / un eiji\nizzen.\n"
    },
    {
      "n": 16,
      "column": "left",
      "text": "Jo tee ne eet gulleht pirms\nne tanna darriſchi/ un teem\n"
    },
    {
      "n": 17,
      "column": "right",
      "text": "Jo tee ehd Maisi tahs\nBesdeewigas/ un dser Wihnu\ntahs Marrasdarrischanas.\n"
    },
    {
      "n": 18,
      "column": "right",
      "text": "Bet to Taifnu Zellinsch\nirr ka tahds spohsch Gaifchums/\neas aust/ un spihd lihds patt lee-\nlu Gaifinu.\n"
    },
    {
      "n": 19,
      "column": "right",
      "text": "To Besdeewigu Zeffch\nirr ka Tumsiba/ tee ne finna/\npahr fo tee krittihg.\n"
    },
    {
      "n": 20,
      "column": "right",
      "text": "Nemt wehra mans Dehls\nmannus Wahrdus/ grees tarvu\nAusfi us mannu Wallodu.\n"
    },
    {
      "n": 21,
      "column": "right",
      "text": "Ne leez tohs no tawahm\nAzzim nosust / furgi tohs no\nSirsdibbina.\n"
    },
    {
      "n": 22,
      "column": "right",
      "text": "Jo tee irr ta Dsihwiba\nteem/ kas to atrohd / un weena\nAhrstes-Sahle wiffahm winnu\nMeefahm.\n"
    },
    {
      "n": 23,
      "column": "right",
      "text": "Pahr wiſfu / kas jafar-\nga/ fargi tarvu Sirdi / jo no\ntahs iseet ta Dsihwiba.\n"
    },
    {
      "n": 24,
      "column": "right",
      "text": "Atstahdina no teviun\nnohst to pahrwehrtitu Mutti/un\nGahnitaju Luhpas lai tahku no\ntew irra.\n"
    },
    {
      "n": 25,
      "column": "right",
      "text": "Lai tawas Azzis taifni\nrauga / un tawi Azzuplakstenti\nlai taifni tawa Preekfcha tur-\nrahg.\n"
    },
    {
      "n": 26,
      "column": "right",
      "text": "Swahrfti tohs Sohtus\ntawo Kahjo/ tad taps wiſſi ta-\nwi Zetti fitprinati.\n"
    },
    {
      "n": 27,
      "column": "right",
      "text": "Ne allojees net pa labbo\nnei pa kreifo Puſſi/ atgreefta-\nwu Kahju no Launa.\n"
    }
  ],
